#include <bits/stdc++.h>
using namespace std;
string temp;
string s;
int main(){
	while(1){
		cin>>temp;
		bool flag=0;
		for(int i=0;i<temp.size();i++){
			if(temp[i]=='E'){
				flag=1;
				break;
			}
			if(temp[i]=='W'||temp[i]=='L'){
				s+=temp[i];
			}
		}
		if(flag){
			break;
		}
	}
	int hlb=0,ljh=0;
	for(int i=0;i<s.size();i++){
		if(s[i]=='W'){
			hlb++;
		}else{
			ljh++;
		}
		if((hlb>=11||ljh>=11)&&abs(hlb-ljh)>=2){
			cout<<hlb<<":"<<ljh<<endl;
			hlb=ljh=0;
		}
	}
	cout<<hlb<<":"<<ljh<<endl;
	cout<<endl;
	hlb=0;ljh=0;
	for(int i=0;i<s.size();i++){
		if(s[i]=='W'){
			hlb++;
		}else{
			ljh++;
		}
		if((hlb>=21||ljh>=21)&&abs(hlb-ljh)>=2){
			cout<<hlb<<":"<<ljh<<endl;
			hlb=ljh=0;
		}
	}
	cout<<hlb<<":"<<ljh;
	return 0;
}
